/** jaram.menu.mapper.DonateMapper.insertDonateReqForm [후원신청서 저장] */
INSERT INTO DONATE_INFO
(
      DONATE_SEQ
    , USER_ID
    , REQ_NAME
    , REQ_PHONE
    , REQ_EMAIL
    , DONATE_AMOUNT
    , DONATE_SURVEY_01
    , DONATE_SURVEY_TEXT_01
    , DONATE_SURVEY_02
    , DONATE_SURVEY_TEXT_02
    , RESI_NUM
    , INPUT_DT
    , INPUT_ID
    , INPUT_NAME
)
VALUE
(
      #{DONATE_SEQ}
    , #{INPUT_ID}
    , #{REQ_NAME}
    , #{REQ_PHONE}
    , #{REQ_EMAIL}
    , #{DONATE_AMOUNT}
    , #{DONATE_SURVEY_01}
    , #{DONATE_SURVEY_TEXT_01}
    , #{DONATE_SURVEY_02}
    , #{DONATE_SURVEY_TEXT_02}
    , #{RESI_NUM}
    , NOW()
    , #{INPUT_ID}
    , #{INPUT_NAME}
    )

mapper.update:
/** jaram.menu.mapper.DonateMapper.updateEncDonateSeq [후원신청서 암호화 시퀀스 저장] */
UPDATE  DONATE_INFO
SET     ENC_DONATE_SEQ = HEX(AES_ENCRYPT(#{DONATE_SEQ}, SHA2('jaramdb@123', 256)))
WHERE   DONATE_SEQ = #{DONATE_SEQ}

mapper.select:
/** jaram.menu.mapper.DonateMapper.selectDonateReqForm [후원신청서 상세 조회] */ SELECT DONATE_SEQ , ENC_DONATE_SEQ , USER_ID , REQ_NAME , REQ_PHONE , REQ_EMAIL , DONATE_AMOUNT , DONATE_SURVEY_01 , DONATE_SURVEY_TEXT_01 , DONATE_SURVEY_02 , DONATE_SURVEY_TEXT_02 , RESI_NUM , INPUT_DT , INPUT_ID , INPUT_NAME FROM DONATE_INFO
DONATE_SEQ = #{DONATE_SEQ}
ENC_DONATE_SEQ = #{ENC_DONATE_SEQ}
